const crypto = require('crypto');
const form = $input.item.json;

const subject = String(form['Subject'] || '').trim();
const grade = String(form['Grade'] || '5').trim();
const lang = String(form['Language'] || 'uz').trim();
const theme = String(form['Theme'] || '').trim();
const qism = String(form['Qism'] || '').trim();
const chapter = String(form['Chapter'] || '1').trim();
const lesson = String(form['Lesson'] || '1').trim();

if (!subject) throw new Error('Subject is required');
if (!chapter || chapter === '0') throw new Error('Chapter number is required');
if (!lesson || lesson === '0') throw new Error('Lesson number is required');

const folderMap = {
  'Matematika': 'math',
  'Ona_tili': 'ona_tili',
  'Ingliz_tili': 'ingliz_tili',
  'Adabiyot': 'adabiyot',
  'Tarix': 'tarix',
  'Geografiya': 'geografiya',
  'Tabiiy_fanlar': 'tabiiy_fanlar',
  'Informatika': 'informatika',
  'Rus_tili': 'rus_tili',
  'Musiqa': 'musiqa',
  'Tasviriy_sanat': 'tasviriy_sanat',
  'Texnologiya': 'texnologiya',
  'Tarbiya': 'tarbiya'
};

const subjectFolder = folderMap[subject] || subject.toLowerCase();
const qismPart = (qism && qism !== 'none') ? '/' + qism : '';
const chapterNum = String(parseInt(chapter, 10)).padStart(2, '0');
const lessonNum = String(parseInt(lesson, 10)).padStart(2, '0');
const chapterUri = `/home/node/nets/books/grade_${grade}/${lang}/${subjectFolder}${qismPart}/chapter_${chapterNum}/lesson_${lessonNum}.txt`;

const taskId = crypto.randomUUID();
const lessonId = `${subjectFolder}_g${grade}_${lang}_ch${chapterNum}_l${lessonNum}`;

return [{ json: {
  task_id: taskId,
  lesson_id: lessonId,
  subject,
  grade: Number(grade),
  lang,
  theme,
  chapter: chapterNum,
  lesson: lessonNum,
  qism: qism || '',
  chapter_uri: chapterUri
} }];

const t = $input.item.json;
if (!t.task_id) throw new Error('No task_id in input: ' + JSON.stringify(t));
return [{ json: {
  task_id: String(t.task_id),
  lesson_id: String(t.lesson_id),
  subject: String(t.subject),
  grade: Number(t.grade),
  lang: String(t.lang),
  theme: String(t.theme || ''),
  chapter: String(t.chapter || '01'),
  qism: String(t.qism || ''),
  chapter_uri: String(t.chapter_uri || '')
}}];

const item = $('Set Task').item.json;
const fs = require('fs');

const chapterPath = item.chapter_uri;

if (!chapterPath) {
  throw new Error('No chapter_uri — use the form trigger to select a chapter.');
}

if (!fs.existsSync(chapterPath)) {
  throw new Error('Chapter file not found: ' + chapterPath + '\nExpected location inside Docker. Place the chapter .txt file there first.');
}

const rawText = fs.readFileSync(chapterPath, 'utf8');

if (!rawText || rawText.trim().length < 10) {
  throw new Error('Chapter file is empty: ' + chapterPath);
}

// Clean the text: remove printer lines, timestamps, duplicate lines
const lines = rawText.split('\n');
const seen = new Set();
const cleaned = [];
for (const line of lines) {
  const s = line.trim();
  // Skip printer/publisher lines
  if (s.includes('SCHOOLBOOK') || s.includes('MATEMATICS')) continue;
  // Skip timestamps like 09/08/24   19:30
  if (/^\d{2}\/\d{2}\/\d{2}/.test(s)) continue;
  // Skip duplicate consecutive lines
  if (seen.has(s) && s.length > 0) continue;
  seen.add(s);
  cleaned.push(s);
}
// Collapse multiple blank lines into one
const chapterText = cleaned.join('\n').replace(/\n{3,}/g, '\n\n').trim();

return [{ json: {
  pdf_text: chapterText,
  task_id: item.task_id,
  lesson_id: item.lesson_id,
  subject: item.subject,
  grade: item.grade,
  lang: item.lang,
  theme: item.theme,
  chapter: item.chapter,
  chapter_uri: item.chapter_uri
} }];

const task = $('Set Task').item.json;
const pdfContent = $json.pdf_text || 'Chapter content unavailable';

const chapterContext = `subject=${task.subject}, grade=${task.grade}, lang=${task.lang}, chapter=${task.chapter}${task.qism ? ', qism=' + task.qism : ''}${task.theme ? ', theme=' + task.theme : ''}`;

const schema = `{
  "topic": "lesson topic name",
  "learning_objectives": ["objective 1", "objective 2"],
  "key_concepts": [{"term": "...", "definition": "..."}],
  "worked_examples": [{"problem": "...", "solution": "..."}],
  "exercises": [{"question": "...", "answer": "..."}],
  "summary": "brief summary of the lesson"
}`;

const payload = {
  model: 'kimi-k2.5',
  messages: [
    { role: 'system', content: 'You are a curriculum extraction assistant. Extract structured lesson content from the provided textbook text. Be concise — do not copy large blocks of text verbatim. Maximum 3 worked examples and 5 exercises.' },
    { role: 'user', content: `CONTEXT: ${chapterContext}\n\nLESSON TEXT:\n${pdfContent}\n\nTASK: Extract the lesson content. Return ONLY valid JSON matching this schema exactly (no markdown, no extra fields):\n${schema}` }
  ],
  response_format: { type: 'json_object' },
  temperature: 1,
  max_tokens: 6000
};

return [{ json: { payload, task_id: task.task_id, lesson_id: task.lesson_id, subject: task.subject, grade: task.grade, lang: task.lang, theme: task.theme || '', chapter: task.chapter, chapter_uri: task.chapter_uri, call_start: Date.now() } }];

const response = $json;
const meta = $('Build Extraction Prompt').item.json;

let lessonJson;
try {
  let raw = response.choices[0].message.content || '';
  raw = raw.replace(/^\s*```json\s*/i, '').replace(/^\s*```\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  if (!raw) throw new Error('empty response from Kimi');
  lessonJson = JSON.parse(raw);
} catch(e) {
  throw new Error('Invalid JSON from extraction: ' + e.message);
}

const fs = require('fs');
try { fs.mkdirSync('/home/node/nets/nets-output', { recursive: true }); } catch(e) {}
const lessonPath = `/home/node/nets/nets-output/${meta.lesson_id}_lesson.json`;
fs.writeFileSync(lessonPath, JSON.stringify(lessonJson, null, 2));

const tokensIn = response.usage?.prompt_tokens || 0;
const tokensOut = response.usage?.completion_tokens || 0;
const costUsd = (tokensIn * 0.60 + tokensOut * 2.50) / 1000000;

return [{ json: {
  lesson_path: lessonPath,
  task_id: meta.task_id,
  lesson_id: meta.lesson_id,
  subject: meta.subject,
  grade: meta.grade,
  lang: meta.lang,
  chapter: meta.chapter,
  chapter_uri: meta.chapter_uri,
  tokens_in: tokensIn,
  tokens_out: tokensOut,
  cost_usd: costUsd
}}];

const task = $('Parse & Save Lesson').item.json;
const allPhases = [
  { id: 'phase_0a', name: 'Theme Preview',      game_refs: [] },
  { id: 'phase_0b', name: 'Flash Cards',         game_refs: [] },
  { id: 'phase_1',  name: 'Memory Sprint',       game_refs: [] },
  { id: 'phase_2',  name: 'Story Mode',          game_refs: [] },
  { id: 'phase_3',  name: 'Game Breaks',         game_refs: ['03_Tile_Match','18_Puzzle_Lock','13_Tic_Tac_Toe_AI'] },
  { id: 'phase_4',  name: 'Real-Life Challenge', game_refs: [] },
  { id: 'phase_5',  name: 'Consolidation',       game_refs: [] },
  { id: 'phase_6',  name: 'Final Boss',          game_refs: [] },
  { id: 'phase_7',  name: 'Reflection',          game_refs: [] }
];

const doneRows = $('Check Done Phases').all();
const donePhaseIds = new Set(doneRows.map(r => r.json.phase_id).filter(Boolean));
const pendingPhases = allPhases.filter(p => !donePhaseIds.has(p.id));
const phasesToRun = pendingPhases.length > 0 ? pendingPhases : allPhases;

return phasesToRun.map(p => ({ json: {
  task_id: task.task_id,
  lesson_id: task.lesson_id,
  subject: task.subject,
  grade: task.grade,
  lang: task.lang,
  lesson_path: task.lesson_path,
  phase_id: p.id,
  phase_name: p.name,
  game_refs: p.game_refs
} }));

const item = $input.item.json;
const fs = require('fs');
const FW = '/home/node/nets/frameworks';

const subjectFileMap = {
  'matematika': 'matematika', 'algebra': 'algebra', 'geometriya': 'geometriya',
  'algebra_va_analiz': 'algebra_va_analiz', 'fizika': 'physics', 'kimyo': 'chemistry',
  'biologiya': 'biology', 'tabiiy_fanlar': 'biology', 'ona_tili': 'ona_tili',
  'adabiyot': 'ona_tili', 'ingliz_tili': 'english', 'rus_tili': 'rus_tili',
  'tarix': 'tarix', 'ozbekiston_tarixi': 'ozbekiston_tarixi', 'jahon_tarixi': 'jahon_tarixi',
  'geografiya': 'tarix', 'informatika': 'matematika'
};
const subjectKey = (item.subject || 'matematika').toLowerCase();
const subjectFile = subjectFileMap[subjectKey] || 'matematika';

// Extract shared header + phase-specific section from subject framework
// This sends ~100% of the relevant rules without truncating anything important
function extractSubjectFramework(fullText, phaseId) {
  // Shared header: everything up to the phase-by-phase tuning section
  const phaseTuningMarker = '## 4. Phase-by-Phase Tuning';
  const headerEnd = fullText.indexOf(phaseTuningMarker);
  const header = headerEnd > -1 ? fullText.slice(0, headerEnd) : fullText.slice(0, 10000);

  // Phase-specific section markers
  const markers = {
    phase_0a: { start: '### 3.4 Pre-Session Tuning',  end: '## 4. Phase-by-Phase' },
    phase_0b: { start: '**0-B Flash Cards',            end: '---\n\n## 4. Phase-by-Phase' },
    phase_1:  { start: '### 4.1 Memory Sprint',        end: '### 4.2 Story Mode' },
    phase_2:  { start: '### 4.2 Story Mode',           end: '### 4.3 Game Breaks' },
    phase_3:  { start: '### 4.3 Game Breaks',          end: '### 4.4 Real-Life' },
    phase_4:  { start: '### 4.4 Real-Life Challenge',  end: '### 4.5 Consolidation' },
    phase_5:  { start: '### 4.5 Consolidation',        end: '### 4.6 Final Boss' },
    phase_6:  { start: '### 4.6 Final Boss',           end: '### 4.7 Reflection' },
    phase_7:  { start: '### 4.7 Reflection',           end: '\n---\n\n## 5.' },
  };

  const m = markers[phaseId];
  if (!m) return header;

  const startIdx = fullText.indexOf(m.start);
  if (startIdx === -1) return header;
  const endIdx = m.end ? fullText.indexOf(m.end, startIdx) : -1;
  const phaseSection = endIdx > -1 ? fullText.slice(startIdx, endIdx) : fullText.slice(startIdx);

  return header + '\n\n---\n\n## PHASE-SPECIFIC RULES FOR THIS CALL\n\n' + phaseSection;
}

let basePrompt = 'You are a NETS homework phase generator for Uzbekistan K-11 students.';
let subjectFramework = '';
let phaseSpec = '';
let outputSchema = '{}';

try { basePrompt = fs.readFileSync(`${FW}/system/phase_worker_base.md`, 'utf8'); } catch(e) {}
try {
  const sf = fs.readFileSync(`${FW}/subjects/${subjectFile}.md`, 'utf8');
  subjectFramework = extractSubjectFramework(sf, item.phase_id);
} catch(e) {}
try { phaseSpec = fs.readFileSync(`${FW}/unified/${item.phase_id}.md`, 'utf8'); } catch(e) { phaseSpec = `Phase: ${item.phase_id}`; }
try { outputSchema = fs.readFileSync(`${FW}/schemas/${item.phase_id}.json`, 'utf8'); } catch(e) {}

let lessonText = 'Lesson content unavailable.';
try { lessonText = fs.readFileSync(item.lesson_path, 'utf8'); } catch(e) {}

const lang = item.lang === 'uz' ? 'Uzbek' : 'Russian';

const systemMessage = [
  `## SYSTEM INVARIANTS\n${basePrompt}`,
  subjectFramework ? `## SUBJECT FRAMEWORK (${item.subject})\n${subjectFramework}` : '',
  phaseSpec ? `## PHASE SPECIFICATION (${item.phase_id})\n${phaseSpec}` : ''
].filter(Boolean).join('\n\n---\n\n');

const userMessage = [
  `## LESSON CONTENT\n${lessonText}`,
  `## TASK CONTEXT\n{"grade": ${item.grade}, "lang": "${item.lang}", "subject": "${item.subject}", "lesson_id": "${item.lesson_id}", "phase_id": "${item.phase_id}"}`,
  `## OUTPUT SCHEMA — match every field name exactly\n${outputSchema}`,
  `## TASK\nGenerate the ${item.phase_id} (${item.phase_name}) phase. Fill every required field. Write all student-facing text in ${lang}. Return ONLY valid JSON — no markdown fences, no extra text.`
].join('\n\n---\n\n');

const payload = {
  model: 'kimi-k2-turbo-preview',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userMessage }
  ],
  response_format: { type: 'json_object' },
  temperature: 1,
  max_tokens: { phase_0a: 16000, phase_0b: 8000, phase_1: 8000, phase_2: 12000, phase_3: 16000, phase_4: 10000, phase_5: 8000, phase_6: 12000, phase_7: 6000 }[item.phase_id] || 4000
};

return [{ json: { payload, task_id: item.task_id, lesson_id: item.lesson_id, phase_id: item.phase_id, phase_name: item.phase_name, subject: item.subject, grade: item.grade, lang: item.lang, lesson_path: item.lesson_path, call_start: Date.now() } }];

const response = $json;
const meta = $('Compose Phase Prompt').item.json;

let phaseJson;
try {
  let raw = response.choices[0].message.content || '';
  raw = raw.replace(/^\s*```json\s*/i, '').replace(/^\s*```\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  if (!raw) throw new Error('empty response from model');
  phaseJson = JSON.parse(raw);
} catch(e) {
  throw new Error(`Phase ${meta.phase_id} invalid JSON: ` + e.message);
}

const tokensIn = response.usage?.prompt_tokens || 0;
const tokensOut = response.usage?.completion_tokens || 0;
const costUsd = (tokensIn * 0.60 + tokensOut * 2.50) / 1000000;
const latency = Date.now() - meta.call_start;
const phaseJsonStr = JSON.stringify(phaseJson).replace(/'/g, "''");

return [{ json: {
  phase_output_json: phaseJsonStr,
  task_id: meta.task_id,
  lesson_id: meta.lesson_id,
  phase_id: meta.phase_id,
  subject: meta.subject,
  grade: meta.grade,
  lang: meta.lang,
  lesson_path: meta.lesson_path,
  tokens_in: tokensIn,
  tokens_out: tokensOut,
  cost_usd: costUsd,
  latency_ms: latency
}}];

const allRows = $input.all();
if (allRows.length === 0) throw new Error('No phase outputs found in DB');

const task_id = allRows[0].json.task_id;
const lesson_id = allRows[0].json.lesson_id;

const phases = {};
allRows.forEach(row => {
  const raw = row.json.output_json;
  phases[row.json.phase_id] = (typeof raw === 'string') ? JSON.parse(raw) : raw;
});

const p0a = phases.phase_0a || {};
const p0b = phases.phase_0b || {};
const p1  = phases.phase_1  || {};
const p2  = phases.phase_2  || {};
const p3  = phases.phase_3  || {};
const p4  = phases.phase_4  || {};
const p5  = phases.phase_5  || {};
const p6  = phases.phase_6  || {};
const p7  = phases.phase_7  || {};

let md = [];
md.push(`# NETS Uy Vazifasi — ${lesson_id}`);
md.push('');

// PHASE 0-A — schema: gate_quote{text,author}, panels[]{number,title,content}, bost_goal
md.push('---\n## PHASE 0-A: MAVZU KO\'RIGI');
if (p0a.gate_quote) { md.push(`> *"${p0a.gate_quote.text}"* — ${p0a.gate_quote.author}`); md.push(''); }
(p0a.panels || []).forEach(p => { md.push(`### Panel ${p.number}: ${p.title}`); md.push(p.content || ''); md.push(''); });
if (p0a.bost_goal) md.push(`**Bugungi Maqsad:** ${p0a.bost_goal}\n`);

// PHASE 0-B — schema: cards[]{number,concept,visual_description,is_common_mistake}
md.push('---\n## PHASE 0-B: FLASH KARTALAR');
(p0b.cards || []).forEach(c => { md.push(`- **${c.concept}** — ${c.visual_description}${c.is_common_mistake ? ' ⚠️' : ''}`); });
md.push('');

// PHASE 1 — schema: questions[]{number,format,prompt,options,answer,tag{bloom,pisa}}
md.push('---\n## PHASE 1: XOTIRA SPRINTI');
(p1.questions || []).forEach(q => {
  md.push(`${q.number}. [${q.format}] ${q.prompt}`);
  if (q.options) q.options.forEach((o, i) => md.push(`   ${String.fromCharCode(65+i)}) ${o}`));
  md.push(`   **Javob:** ${q.answer}`);
  if (q.tag) md.push(`   *[Bloom: ${q.tag.bloom} | PISA: ${q.tag.pisa}]*`);
  md.push('');
});
if (p1.adaptation_rule) md.push(`*${p1.adaptation_rule}*\n`);

// PHASE 2 — schema: story_text (string), checkpoints[]{number,question,answer,tag}
md.push('---\n## PHASE 2: HIKOYA REJIMI');
if (p2.story_text) { md.push(p2.story_text); md.push(''); }
(p2.checkpoints || []).forEach(cp => {
  md.push(`**Savol ${cp.number}:** ${cp.question}`);
  md.push(`**Javob:** ${cp.answer}`);
  if (cp.tag) md.push(`*[Bloom: ${cp.tag.bloom} | PISA: ${cp.tag.pisa}]*`);
  md.push('');
});

// PHASE 3 — schema: games[]{game_id,catalog,title,items[]{content,hint,tag},answer_key}
md.push('---\n## PHASE 3: O\'YIN TANAFFUSLARI');
(p3.games || []).forEach((game, gi) => {
  md.push(`### ${gi+1}-o'yin: ${game.title} [${game.catalog}]`);
  (game.items || []).forEach((item, ii) => {
    const content = typeof item.content === 'string' ? item.content : JSON.stringify(item.content);
    md.push(`${ii+1}. ${content}`);
    if (item.hint) md.push(`   *Yordam: ${item.hint}*`);
    if (item.tag) md.push(`   *[Bloom: ${item.tag.bloom} | PISA: ${item.tag.pisa}]*`);
  });
  if (game.answer_key) md.push(`**Javoblar:** ${game.answer_key}`);
  md.push('');
});

// PHASE 4 — schema: scenario{title,emoji,body_text}, questions[]{number,text,tag}, full_answer_key
md.push('---\n## PHASE 4: HAYOTIY VAZIFA');
if (p4.scenario) {
  md.push(`### ${p4.scenario.emoji || ''} ${p4.scenario.title}`);
  md.push(p4.scenario.body_text || '');
  md.push('');
}
(p4.questions || []).forEach(q => {
  md.push(`${q.number}. ${q.text}`);
  if (q.tag) md.push(`   *[Bloom: ${q.tag.bloom} | PISA: ${q.tag.pisa}]*`);
  md.push('');
});
if (p4.full_answer_key) md.push(`**Javoblar:** ${p4.full_answer_key}\n`);

// PHASE 5 — schema: technique, content_structure, entry_card, exercises[]{number,title,items[]{label,concept,vivid_image},interaction_model}, transition_line
md.push('---\n## PHASE 5: MUSTAHKAMLASH');
if (p5.technique) md.push(`**Usul:** ${p5.technique} (${p5.content_structure})`);
if (p5.entry_card) md.push(p5.entry_card + '\n');
(p5.exercises || []).forEach(ex => {
  md.push(`#### ${ex.number}. ${ex.title} [${ex.interaction_model}]`);
  (ex.items || []).forEach(it => {
    md.push(`- **${it.label}** — ${it.concept}`);
    if (it.vivid_image) md.push(`  _${it.vivid_image}_`);
  });
  md.push('');
});
if (p5.transition_line) md.push(`*${p5.transition_line}*\n`);

// PHASE 6 — schema: boss_hp, questions[]{number,difficulty,damage,question_text,socratic_hints[],rubric{full,partial,minimal},tag}
md.push('---\n## PHASE 6: YAKUNIY BOSS');
if (p6.boss_hp) md.push(`**Boss HP:** ${p6.boss_hp}\n`);
(p6.questions || []).forEach(q => {
  const dmg = Math.abs(q.damage || 0);
  md.push(`${q.number}. [${(q.difficulty||'').toUpperCase()} | -${dmg} HP] ${q.question_text}`);
  if (q.socratic_hints && q.socratic_hints.length) {
    q.socratic_hints.forEach((h, i) => md.push(`   Yordam ${i+1}: ${h}`));
  }
  if (q.rubric) md.push(`   *To'liq ball: ${q.rubric.full}*`);
  if (q.tag) md.push(`   *[Bloom: ${q.tag.bloom} | PISA: ${q.tag.pisa}]*`);
  md.push('');
});

// PHASE 7 — schema: results{strong_topics,weak_topics}, micro_exercises[]{number,exercise,answer}, bost_recall, reflection_prompts[], spaced_repetition_schedule[], closing_line
md.push('---\n## PHASE 7: FIKRLASH');
if (p7.results) {
  if (p7.results.strong_topics && p7.results.strong_topics.length) md.push(`**Kuchli:** ${p7.results.strong_topics.join(', ')}`);
  if (p7.results.weak_topics && p7.results.weak_topics.length) md.push(`**Zaif:** ${p7.results.weak_topics.join(', ')}`);
  md.push('');
}
(p7.micro_exercises || []).forEach(ex => {
  md.push(`${ex.number}. ${ex.exercise}`);
  md.push(`   **Javob:** ${ex.answer}`);
  md.push('');
});
if (p7.bost_recall) md.push(`**BOST:** ${p7.bost_recall}\n`);
(p7.reflection_prompts || []).forEach(p => { md.push(`• ${typeof p === 'string' ? p : p.prompt_text}`); });
if (p7.spaced_repetition_schedule && p7.spaced_repetition_schedule.length) md.push(`\n**Qayta ko'rish:** ${p7.spaced_repetition_schedule.join(' → ')}`);
if (p7.closing_line) md.push(`\n*${p7.closing_line}*`);

const fs = require('fs');
const mdPath = `/home/node/nets/nets-output/${lesson_id}_homework.md`;
fs.writeFileSync(mdPath, md.join('\n'));

return [{ json: { md_path: mdPath, task_id, lesson_id } }];
